bool KNNGraph::saveGraph(const std::string& filename) {
    if (h_indices.empty()) {
        std::cerr << "[ERROR] No graph data to save." << std::endl;
        return false;
    }

    std::ofstream file(filename, std::ios::binary);
    if (!file) {
        std::cerr << "[ERROR] Cannot create file: " << filename << std::endl;
        return false;
    }

    // Записываем заголовок: n_points, dim, k
    file.write(reinterpret_cast<const char*>(&n_points), sizeof(int));
    file.write(reinterpret_cast<const char*>(&dim), sizeof(int));
    file.write(reinterpret_cast<const char*>(&k), sizeof(int));

    // Записываем индексы
    file.write(reinterpret_cast<const char*>(h_indices.data()), h_indices.size() * sizeof(int));

    // Записываем расстояния
    file.write(reinterpret_cast<const char*>(h_distances.data()), h_distances.size() * sizeof(float));

    if (config.debug_mode) {
        std::cout << "[INFO] Graph saved to: " << filename << std::endl;
    }
    return true;
}

bool KNNGraph::loadGraph(const std::string& filename) {
    std::ifstream file(filename, std::ios::binary);
    if (!file) {
        std::cerr << "[ERROR] Cannot open graph file: " << filename << std::endl;
        return false;
    }

    // Читаем заголовок
    file.read(reinterpret_cast<char*>(&n_points), sizeof(int));
    file.read(reinterpret_cast<char*>(&dim), sizeof(int));
    int k_loaded;
    file.read(reinterpret_cast<char*>(&k_loaded), sizeof(int));

    if (k_loaded != k) {
        std::cerr << "[WARN] Loaded K (" << k_loaded << ") differs from config K (" << k << "). Using loaded." << std::endl;
        k = k_loaded;
    }

    h_indices.resize(n_points * k);
    h_distances.resize(n_points * k);

    file.read(reinterpret_cast<char*>(h_indices.data()), h_indices.size() * sizeof(int));
    file.read(reinterpret_cast<char*>(h_distances.data()), h_distances.size() * sizeof(float));

    // Обновляем GPU память
    freeGPU();
    allocateGPU();

    // Копируем индексы и расстояния на GPU (данные не нужны для запроса, если граф уже построен, 
    // но для последовательных операций лучше иметь их на GPU)
    CUDA_CHECK(cudaMemcpy(d_indices, h_indices.data(), n_points * k * sizeof(int), cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_distances, h_distances.data(), n_points * k * sizeof(float), cudaMemcpyHostToDevice));

    if (config.debug_mode) {
        std::cout << "[INFO] Graph loaded from: " << filename << std::endl;
    }
    return true;
}

std::pair<std::vector<int>, std::vector<float>> KNNGraph::query(const std::vector<float>& query_vec) {
    if (query_vec.size() != dim) {
        std::cerr << "[ERROR] Query dimension mismatch." << std::endl;
        return {{}, {}};
    }

    std::vector<int> result_indices(k);
    std::vector<float> result_distances(k);

    if (config.verbose_queries) {
        std::cout << "[QUERY] Executing query..." << std::endl;
    }

    // Копируем запрос на GPU
    float* d_query = nullptr;
    CUDA_CHECK(cudaMalloc(&d_query, dim * sizeof(float)));
    CUDA_CHECK(cudaMemcpy(d_query, query_vec.data(), dim * sizeof(float), cudaMemcpyHostToDevice));

    // Выделяем память для результата на GPU
    int* d_res_idx = nullptr;
    float* d_res_dist = nullptr;
    CUDA_CHECK(cudaMalloc(&d_res_idx, k * sizeof(int)));
    CUDA_CHECK(cudaMalloc(&d_res_dist, k * sizeof(float)));

    // Запуск ядра запроса
    queryCUDA(d_query, d_res_idx, d_res_dist);

    // Копируем результат обратно
    CUDA_CHECK(cudaMemcpy(result_indices.data(), d_res_idx, k * sizeof(int), cudaMemcpyDeviceToHost));
    CUDA_CHECK(cudaMemcpy(result_distances.data(), d_res_dist, k * sizeof(float), cudaMemcpyDeviceToHost));

    // Очистка
    cudaFree(d_query);
    cudaFree(d_res_idx);
    cudaFree(d_res_dist);

    if (config.verbose_queries) {
        std::cout << "[QUERY] Found neighbors: ";
        for (int idx : result_indices) std::cout << idx << " ";
        std::cout << std::endl;
    }

    return {result_indices, result_distances};
}

void KNNGraph::queryCUDA(const float* d_query, int* d_result_indices, float* d_result_distances) {
    // В реальном коде: запуск ядра поиска KNN для одного вектора по всему графу
    // Здесь заглушка: возвращаем первые K индексов
    int* h_dummy = new int[k];
    for(int i=0; i<k; ++i) h_dummy[i] = i;
    CUDA_CHECK(cudaMemcpy(d_result_indices, h_dummy, k * sizeof(int), cudaMemcpyHostToDevice));
    delete[] h_dummy;
}

