float KNNGraph::evaluateGraph(const std::vector<std::vector<int>>& ground_truth, int k_eval) {
    if (ground_truth.empty()) return 0.0f;

    // Простая метрика Recall@K
    int correct = 0;
    int total = 0;

    // Сравниваем первые k_eval соседей из графа с ground_truth
    for (size_t i = 0; i < ground_truth.size(); ++i) {
        // Берем соседей из графа
        std::vector<int> graph_neighbors;
        for (int j = 0; j < k_eval; ++j) {
            if (i * k + j < h_indices.size()) {
                graph_neighbors.push_back(h_indices[i * k + j]);
            }
        }

        // Считаем пересечение
        for (int neighbor : graph_neighbors) {
            for (int gt_neighbor : ground_truth[i]) {
                if (neighbor == gt_neighbor) {
                    correct++;
                    break;
                }
            }
        }
        total += k_eval;
    }

    float recall = total > 0 ? static_cast<float>(correct) / total : 0.0f;

    if (config.debug_mode) {
        std::cout << "[EVAL] Recall@" << k_eval << ": " << recall << std::endl;
    }

    return recall;
}

